app.post('/api/booking', async (req, res) => {
  try {
    const { name, phone, address, size, type, date, time, notes, price, companyName } = req.body;
    if (!name || !phone || !address) {
      return res.status(400).json({ error: 'name, phone, address are required' });
    }
    const { data, error } = await supabase
      .from('bookings')
      .insert([{
        name,
        phone: phone.replace(/-/g, ''),
        address,
        size: size ? parseInt(size) : null,
        type: type || '矛聻聟矛拢录 矛聽聞 矛虏颅矛聠聦',
        preferred_date: date || null,
        preferred_time: time || null,
        notes: notes || null,
        price: price ? parseInt(price) : null,
        company_name: companyName || '矛聥赂矛聥赂铆聛麓毛娄掳',
        status: 'pending'
      }])
      .select()
      .single();
    if (error) return res.status(500).json({ error: 'DB_ERROR', detail: error.message, code: error.code });
    // SMS (ignore failure)
    try {
      const op = process.env.COOLSMS_FROM, ak = process.env.COOLSMS_API_KEY;
      const as_ = process.env.COOLSMS_API_SECRET, fp = process.env.COOLSMS_FROM;
      if (op && ak && as_ && fp) {
        const crypto = require('crypto');
        const ts = new Date().toISOString().replace(/[^0-9]/g,'').slice(0,14);
        const salt = Math.random().toString(36).substr(2,16);
        const sig = crypto.createHmac('sha256', as_).update(ts+salt).digest('hex');
        const msg = '[SSAK] '+name+'('+phone+') '+date+' '+time+' '+type+' '+size+'py '+address;
        fetch('https://api.coolsms.co.kr/messages/v4/send', {
          method:'POST',
          headers:{'Content-Type':'application/json','Authorization':'HMAC-SHA256 apiKey='+ak+', date='+ts+', salt='+salt+', signature='+sig},
          body: JSON.stringify({message:{to:op,from:fp,text:msg}})
        }).catch(e=>console.log('SMS fail:',e.message));
      }
    } catch(se) { console.log('SMS error:',se.message); }
    res.json({ success: true, data });
  } catch (err) {
    console.error('booking error:', err);
    res.status(500).json({ error: 'SERVER_ERROR: '+err.message, detail: String(err) });
  }
});

